INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('TITAN_1: Le email sequence step optimization: le step 1 (intro) doit avoir un OR > 25%. Si non → changer le sujet. Le step 3 (valeur) doit avoir le plus de clics.', 'Email steps: step 1 OR > 25% sinon changer sujet. Step 3 = plus de clics', 'email', 'best_practice', 0.85, 'titan', 'system'),
('TITAN_2: Le commercial forecast accuracy improvement: mesurer chaque mois le forecast vs reel. Si ecart > 25% → revoir les criteres de stage progression.', 'Forecast accuracy: mensuel forecast vs reel. Ecart > 25% = revoir criteres', 'commercial', 'best_practice', 0.82, 'titan', 'system'),
('TITAN_3: Le content engagement decay analysis: si l engagement moyen baisse de 20%+ sur 2 semaines → changer de format ou de sujet. L audience s ennuie.', 'Engagement decay: -20% sur 2 sem = changer format/sujet. Audience s ennuie', 'content', 'insight', 0.82, 'titan', 'system'),
('TITAN_4: Le SEO URL structure optimization: urls courtes et descriptives (domain.com/sujet-article) rankent mieux que les urls longues avec parametres.', 'URL SEO: courtes descriptives > longues parametrees', 'seo', 'best_practice', 0.85, 'titan', 'system'),
('TITAN_5: Le ad conversion window setting: pour les produits a achat rapide (e-commerce) = 7-day click. Pour les cycles longs (SaaS B2B) = 28-day click.', 'Conversion window: rapide = 7d click. Long cycle = 28d click', 'ads', 'best_practice', 0.82, 'titan', 'system'),
('TITAN_6: Le DM Instagram prospect profiling: avant d envoyer un DM, analyser: bio (besoins), derniers posts (activite), stories (personnalite), followers (taille business).', 'DM profiling: bio + posts + stories + followers avant DM', 'dm_instagram', 'best_practice', 0.82, 'titan', 'system'),
('TITAN_7: Le WhatsApp status (stories) marketing: poster 1-2 statuts par jour (offre, behind-scenes, temoignage). 35% des contacts les voient. Canal sous-exploite.', 'WhatsApp status: 1-2/jour. 35% contacts les voient. Sous-exploite', 'whatsapp', 'insight', 0.78, 'titan', 'system'),
('TITAN_8: Le chatbot fallback message design: jamais "je ne comprends pas". Proposer: 1) reformuler, 2) choisir un sujet populaire, 3) parler a un humain. Toujours donner des options.', 'Chatbot fallback: reformuler + sujet populaire + humain. Toujours des options', 'chatbot', 'best_practice', 0.85, 'titan', 'system'),
('TITAN_9: Le GMaps review generation funnel: service excellent → demande verbale → QR code → lien Google → rappel email J+1 → rappel SMS J+3. Multi-touch = plus d avis.', 'GMaps review funnel: verbal → QR → lien → email J1 → SMS J3 = plus d avis', 'gmaps', 'best_practice', 0.82, 'titan', 'system'),
('TITAN_10: Le TikTok niche domination strategy: poster 1 video/jour pendant 90 jours dans 1 niche specifique. L algorithme vous categorise comme expert → recommande a l audience niche.', 'TikTok niche: 1/jour × 90j 1 niche = algo categorise expert → recommande', 'tiktok_comments', 'best_practice', 0.82, 'titan', 'system'),
('TITAN_11: Le CEO agent communication clarity: chaque message au client doit repondre a 3 questions: 1) qu est-ce qui se passe? 2) qu est-ce que ca veut dire? 3) que doit-on faire?', 'CEO comm: qu est-ce qui se passe + qu est-ce que ca veut dire + que faire?', 'ceo', 'best_practice', 0.88, 'titan', 'system'),
('TITAN_12: Le retention value realization tracking: definir pour chaque client CE QUE succes veut dire. Tracker mensuellement. Si pas atteint → intervention.', 'Value realization: definir succes par client. Tracker mensuel. Pas atteint = intervention', 'retention', 'best_practice', 0.85, 'titan', 'system'),
('TITAN_13: Le onboarding friction mapping: lister chaque clic entre signup et aha moment. Compter. Objectif: < 7 clics. Chaque clic elimine = +5% activation.', 'Friction mapping: compter clics signup→aha. < 7 clics. -1 clic = +5% activation', 'onboarding', 'best_practice', 0.85, 'titan', 'system'),
('TITAN_14: Le comptable monthly financial narrative: pas juste les chiffres mais L HISTOIRE. "Le MRR a augmente de 15% grace a 3 nouveaux clients Pro, mais le churn a augmente a cause de..."', 'Financial narrative mensuel: l histoire derriere les chiffres, pas juste les chiffres', 'comptable', 'best_practice', 0.80, 'titan', 'system'),
('TITAN_15: Le RH performance conversation framework: start with strengths → discuss areas for growth → agree on 2-3 specific actions → set timeline → follow up.', 'Performance conversation: strengths → growth → 2-3 actions → timeline → follow up', 'rh', 'best_practice', 0.80, 'titan', 'system'),
('TITAN_16: Le marketing brand storytelling arc: origin story (pourquoi on existe) → mission (ce qu on change) → vision (ou on va) → proof (resultats) → invitation (rejoignez-nous).', 'Brand storytelling: origin → mission → vision → proof → invitation', 'marketing', 'best_practice', 0.82, 'titan', 'system'),
('TITAN_17: Le cross-agent feedback loop: chaque agent recoit le feedback des autres agents. L email informe le contenu, le commercial informe les ads, le chatbot informe le FAQ.', 'Cross-agent feedback: email→contenu, commercial→ads, chatbot→FAQ', NULL, 'best_practice', 0.85, 'titan', 'system'),
('TITAN_18: Le customer journey moment of truth: les 5 moments critiques: 1) premiere visite site, 2) signup, 3) premiere utilisation, 4) premier resultat, 5) premier paiement.', 'Moments of truth: visite + signup + utilisation + resultat + paiement', NULL, 'insight', 0.85, 'titan', 'system'),
('TITAN_19: Le KeiroAI cross-pollination engine: insights d un secteur (restaurant) sont adaptes et proposes a un autre secteur similaire (traiteur, cafe). Transfert de connaissances.', 'Cross-pollination: insights restaurant → adapter pour traiteur/cafe', NULL, 'best_practice', 0.82, 'titan', 'system'),
('TITAN_20: Le KeiroAI agent performance leaderboard: classer les agents par ROI (resultats / cout API) chaque semaine. Les agents les plus performants = plus de budget.', 'Agent leaderboard: ROI hebdo (resultats/cout API). Performants = plus budget', 'ceo', 'best_practice', 0.85, 'titan', 'system'),
('TITAN_21: Le email re-engagement advanced: segmenter les inactifs en 3 groupes: 30-60j (message valeur), 60-90j (offre speciale), 90j+ (au revoir + desinscrire si pas de reaction).', 'Re-engagement: 30-60j valeur, 60-90j offre, 90j+ au revoir/desinscrire', 'email', 'best_practice', 0.82, 'titan', 'system'),
('TITAN_22: Le commercial deal qualification matrix: fit (secteur+taille+besoin) × urgence (timeline+douleur) × ability (budget+DM) = score 1-125. > 75 = deal qualifie.', 'Qualification: fit × urgence × ability. Score 1-125. > 75 = qualifie', 'commercial', 'best_practice', 0.82, 'titan', 'system'),
('TITAN_23: Le content consistency signal: poster a heure fixe chaque jour entraine l audience a attendre le contenu. L algorithme aussi est entraine et pousse plus.', 'Content heure fixe: audience entraine + algorithme entraine = plus de push', 'content', 'insight', 0.82, 'titan', 'system'),
('TITAN_24: Le SEO heading hierarchy: H1 (1 seul, titre principal) → H2 (sections) → H3 (sous-sections) → H4 (details). Jamais sauter de niveau. Google lit la hierarchie.', 'SEO headings: H1 unique → H2 sections → H3 sous → H4 details. Pas sauter', 'seo', 'best_practice', 0.85, 'titan', 'system'),
('TITAN_25: Le ad learning phase respect: pendant la learning phase (50 conversions), ne PAS modifier le budget, l audience ou la creative. Laisser l algorithme apprendre.', 'Learning phase: 50 conv sans modifier budget/audience/creative. Laisser apprendre', 'ads', 'best_practice', 0.88, 'titan', 'system'),
('TITAN_26: Le DM Instagram warm intro via comment: commenter avec valeur sur 3-5 posts du prospect AVANT d envoyer le DM. Le prospect vous reconnait → taux de reponse 3-5x.', 'DM warm via comment: 3-5 posts avant DM = 3-5x taux reponse', 'dm_instagram', 'best_practice', 0.85, 'titan', 'system'),
('TITAN_27: Le WhatsApp interactive list message: proposer une liste de choix (max 10 options) au lieu de demander au client de taper. +60% taux de reponse vs texte libre.', 'WhatsApp interactive list: 10 options max = +60% reponse vs texte libre', 'whatsapp', 'insight', 0.82, 'titan', 'system'),
('TITAN_28: Le chatbot personality consistency: le chatbot doit avoir le meme ton, le meme style et les memes expressions dans CHAQUE conversation. Incoherent = perte de confiance.', 'Chatbot personality consistante: meme ton/style/expressions CHAQUE conversation', 'chatbot', 'best_practice', 0.82, 'titan', 'system'),
('TITAN_29: Le GMaps post scheduling strategy: publier le Google Post le jour de la semaine ou le plus de gens recherchent votre service. Restaurant = mardi-jeudi, coiffeur = lundi.', 'GMaps post timing: jour de plus haute recherche service. Restaurant mar-jeu, coiffeur lun', 'gmaps', 'best_practice', 0.78, 'titan', 'system'),
('TITAN_30: Le TikTok comment reply video: repondre aux commentaires populaires avec une VIDEO (pas du texte). C est le growth hack #1 sur TikTok en 2026.', 'TikTok reply video aux commentaires = growth hack #1 2026', 'tiktok_comments', 'best_practice', 0.85, 'titan', 'system'),
('TITAN_31: Le CEO monthly business review: 1) MRR vs objectif, 2) top 3 reussites, 3) top 3 echecs + learnings, 4) NPS, 5) plan mois prochain. Partager avec toute l equipe.', 'CEO monthly: MRR + 3 reussites + 3 echecs + NPS + plan. Partager equipe', 'ceo', 'best_practice', 0.82, 'titan', 'system'),
('TITAN_32: Le retention proactive success check: contacter CHAQUE nouveau client a J+7 pour verifier qu il obtient de la valeur. Pas attendre qu il se plaigne.', 'Proactive check J+7: verifier valeur chaque nouveau client. Pas attendre plainte', 'retention', 'best_practice', 0.88, 'titan', 'system'),
('TITAN_33: Le onboarding template selection: a l inscription, proposer 3-5 templates par secteur (restaurant/coach/ecommerce). Le template adapte = aha moment 3x plus rapide.', 'Templates onboarding par secteur: 3-5 templates = aha 3x plus rapide', 'onboarding', 'best_practice', 0.85, 'titan', 'system'),
('TITAN_34: Le comptable expense tracking automation: connecter la carte bancaire a un outil de compta (Pennylane, Qonto). Chaque depense est automatiquement categorisee.', 'Expense tracking auto: carte → compta Pennylane/Qonto = categorisation auto', 'comptable', 'best_practice', 0.80, 'titan', 'system'),
('TITAN_35: Le RH exit interview insights: documenter les raisons de depart de CHAQUE employe. Apres 10 departs, les patterns revelent les vrais problemes de l entreprise.', 'Exit interview: documenter raisons. 10 departs → patterns = vrais problemes', 'rh', 'best_practice', 0.80, 'titan', 'system'),
('TITAN_36: Le marketing experimentation velocity: 1 experiment/semaine minimum. Hypothese → test → mesure → learn. Les entreprises qui testent le plus = celles qui croissent le plus.', 'Experimentation: 1/sem min. Hypothese→test→mesure→learn. Plus test = plus croissance', 'marketing', 'best_practice', 0.85, 'titan', 'system'),
('TITAN_37: Le unified customer score: tous les agents contribuent au score: email engagement (20%) + site behavior (20%) + social interaction (15%) + CRM qualification (25%) + support health (20%).', 'Unified score: email 20% + site 20% + social 15% + CRM 25% + support 20%', NULL, 'best_practice', 0.85, 'titan', 'system'),
('TITAN_38: Le real-time opportunity routing: quand un prospect visite la page pricing → alerte CEO + commercial dans les 5 minutes. Le timing est critique.', 'Opportunity routing: pricing visit → alerte CEO + commercial 5 min. Timing critique', NULL, 'best_practice', 0.85, 'titan', 'system'),
('TITAN_39: Le KeiroAI RAG contextual retrieval: le RAG ne cherche pas juste par mots-cles mais par CONTEXTE. Si un agent email cherche "taux ouverture bas", il trouve les solutions specifiques.', 'RAG contextuel: recherche par contexte pas mots-cles. Solutions specifiques', NULL, 'insight', 0.85, 'titan', 'system'),
('TITAN_40: Le KeiroAI perpetual improvement: chaque jour, les agents sont un peu meilleurs qu hier. Chaque semaine, le RAG est plus riche. Chaque mois, l intelligence est superieure.', 'KeiroAI perpetual: chaque jour meilleur, chaque semaine plus riche, chaque mois superieur', 'ceo', 'insight', 0.90, 'titan', 'system'),
('TITAN_41: Le email personalization at scale mastery: utiliser les merge tags + conditional content + dynamic sections pour que CHAQUE email semble ecrit a la main. Scalable et personnel.', 'Email perso at scale: merge + conditional + dynamic = semble ecrit a la main', 'email', 'best_practice', 0.85, 'titan', 'system'),
('TITAN_42: Le commercial social selling daily routine: 15 min/jour: 5 commentaires LinkedIn, 3 likes posts prospects, 2 DMs personnalises, 1 post de valeur. Resultat en 30 jours.', 'Social selling routine: 5 comments + 3 likes + 2 DMs + 1 post/jour. Resultat 30j', 'commercial', 'best_practice', 0.82, 'titan', 'system'),
('TITAN_43: Le content data storytelling: les contenus qui utilisent des donnees originales (etude, sondage, analyse) sont partages 6x plus et generent 3x plus de backlinks.', 'Data storytelling: donnees originales = 6x partages + 3x backlinks', 'content', 'insight', 0.82, 'titan', 'system'),
('TITAN_44: Le SEO Google Search Console mastery: filtrer par position 8-20 + impressions > 100 = mots-cles presque en page 1. Optimiser ces pages = quick wins.', 'GSC: position 8-20 + impressions > 100 = presque page 1. Quick wins', 'seo', 'best_practice', 0.88, 'titan', 'system'),
('TITAN_45: Le ad testing statistical significance: minimum 1000 impressions par variante ET 50+ conversions pour conclure un test. Avant = pas assez de data.', 'Ad test significance: 1000 impressions + 50 conversions minimum pour conclure', 'ads', 'best_practice', 0.82, 'titan', 'system'),
('TITAN_46: Le DM Instagram trust building: ne jamais DM quelqu un sans avoir interagi avec son contenu d abord. Le DM froid = taux de reponse 5%. Le DM chaud = 40%.', 'DM trust: interagir avant DM. Froid = 5%. Chaud = 40%', 'dm_instagram', 'insight', 0.88, 'titan', 'system'),
('TITAN_47: Le WhatsApp quick reply buttons: les messages avec 3 boutons de reponse rapide ont un taux de reponse de 65% vs 35% pour les messages texte.', 'WhatsApp quick reply 3 boutons = 65% reponse vs 35% texte', 'whatsapp', 'insight', 0.82, 'titan', 'system'),
('TITAN_48: Le chatbot learning from failures: chaque conversation echouee (escalade, abandon) est analysee pour identifier le probleme et ajouter la reponse manquante.', 'Chatbot learning: conversations echouees → analyser → ajouter reponse manquante', 'chatbot', 'best_practice', 0.85, 'titan', 'system'),
('TITAN_49: Le GMaps photo geo-tagging: les photos prises sur place (avec GPS dans les metadata EXIF) ont plus de poids pour le ranking local que les photos uploadees depuis un bureau.', 'GMaps photos geo-tag EXIF sur place = plus de poids ranking local', 'gmaps', 'insight', 0.78, 'titan', 'system'),
('TITAN_50: Le TikTok content pillar rotation: 5 piliers de contenu tournes chaque semaine. Lundi edu, mardi storytelling, mercredi trending, jeudi BTS, vendredi divertissement.', 'TikTok 5 piliers: lun edu, mar story, mer trend, jeu BTS, ven fun', 'tiktok_comments', 'best_practice', 0.80, 'titan', 'system')
